    rec = {
        "pattern_id": pattern_id,
        "iteration": iteration,
        "parent_id": parent_id,
        "sample_id": str(sample_id),
        "variables": merged_vars,   # 更新后的参数（已 merge + clip）
        "metrics": metrics,         # 对应分数/指标
        "timestamp": time.time(),
        "program_uuid": str(program_obj.get("id", "")),
    }
    with open(out_path, "w", encoding="utf-8") as f:
        json.dump(rec, f, ensure_ascii=False, indent=2)


