"""
Prompt sampling for OpenEvolve (Bootcamp-style).
- Reduce noisy/verbose text in evolution_history.
- Make prompt rendering safe with str.format (escape braces in inserted text).
- Optionally keep state JSON minimal to avoid messy/too-long prompts.
"""
import logging
import random
import json
import os
import sys
import time
import hashlib
from typing import Any, Dict, List, Optional, Union
from openevolve.config import PromptConfig
from openevolve.prompt.templates import TemplateManager
from openevolve.utils.metrics_utils import (
    get_fitness_score,
    format_feature_coordinates,
)
logger = logging.getLogger(__name__)
_DUMPED_ONCE_BY_PID = set()

class PromptSampler:
    """Generates prompts for code evolution"""
    def __init__(self, config: PromptConfig):
        self.config = config
        self.template_manager = TemplateManager(custom_template_dir=config.template_dir)
        self.system_template_override = None
        self.user_template_override = None
        if not hasattr(logger, "_prompt_sampler_logged"):
            logger.info("Initialized prompt sampler")
            logger._prompt_sampler_logged = True
    def set_templates(
        self,
        system_template: Optional[str] = None,
        user_template: Optional[str] = None
    ) -> None:
        self.system_template_override = system_template
        self.user_template_override = user_template
        logger.info(f"Set custom templates: system={system_template}, user={user_template}")
    # ----------------------------- JSON helpers -----------------------------
    def _try_load_json(self, text: str) -> Optional[Any]:
        if not isinstance(text, str):
            return None
        s = text.strip()
        if not s:
            return None
        if not (s.startswith("{") or s.startswith("[")):
            return None
        try:
            return json.loads(s)
        except Exception:
            return None
    def _pretty_json(self, text: str) -> str:
        obj = self._try_load_json(text)
        if obj is None:
            return text
        try:
            return json.dumps(obj, ensure_ascii=False, indent=2)
        except Exception:
            return text
    def _escape_braces_for_format(self, s: str) -> str:
        """
        Escape literal braces so Python str.format won't treat them as placeholders.
        This is REQUIRED if we inject JSON/code containing '{' '}' into a format-template.
        """
        if not isinstance(s, str) or not s:
            return s
        return s.replace("{", "{{").replace("}", "}}")
    def _json_vars_preview(self, program_text: str, max_items: int = 10) -> str:
        """
        Build a short preview line from a JSON program that contains "variables".
        Used to avoid dumping full state JSON when not needed.
        """
        obj = self._try_load_json(program_text) if isinstance(program_text, str) else None
        if not isinstance(obj, dict):
            return ""
        vars_dict = obj.get("variables")
        if not isinstance(vars_dict, dict):
            return ""
        keys = list(vars_dict.keys())
        preview_k = keys[: min(max_items, len(keys))]
        pairs = []
        for k in preview_k:
            v = vars_dict.get(k)
            if isinstance(v, (str, int, float)):
                pairs.append(f"{k}={v}")
        suffix = "..." if len(keys) > len(preview_k) else ""
        return f"参数数量：{len(keys)}；示例：{', '.join(pairs)}{suffix}"
    def _maybe_shorten_state_json(self, text: str, title: str) -> str:
        """
        Keep prompts close to your desired format:
        - By default: do NOT dump huge state JSON blocks into the user prompt
          (they are noisy, and they contain braces that can break format()).
        - But still allow keeping full JSON if environment variable is set.
        """
        keep_full = os.getenv("OPENEOLVE_KEEP_STATE_JSON", "1") in ("1", "true", "True", "yes", "YES")
        if keep_full:
            return self._pretty_json(text) if isinstance(text, str) else (text or "")
        # minimal view
        preview = self._json_vars_preview(text)
        if preview:
            return f"{title}：{preview}"
        # If not parseable, just keep a short truncated slice
        if isinstance(text, str) and text.strip():
            s = text.strip().replace("\n", " ")
            if len(s) > 200:
                s = s[:200] + "..."
            return f"{title}：{s}"
        return ""
    # ----------------------------- prompt build -----------------------------
    def build_prompt(
        self,
        current_program: str = "",
        parent_program: str = "",
        initial_program: str = "",
        program_metrics: Optional[Dict[str, float]] = None,
        previous_programs: Optional[List[Dict[str, Any]]] = None,
        top_programs: Optional[List[Dict[str, Any]]] = None,
        inspirations: Optional[List[Dict[str, Any]]] = None,
        language: str = "python",
        evolution_round: int = 0,
        diff_based_evolution: bool = True,
        template_key: Optional[str] = None,
        program_artifacts: Optional[Dict[str, Union[str, bytes]]] = None,
        feature_dimensions: Optional[List[str]] = None,
        **kwargs: Any,
    ) -> Dict[str, str]:
        program_metrics = program_metrics or {}
        previous_programs = previous_programs or []
        top_programs = top_programs or []
        inspirations = inspirations or []
        feature_dimensions = feature_dimensions or []
        parsed_current = self._try_load_json(current_program)
        is_json_task = (language or "").lower() == "json" or (parsed_current is not None)
        language_for_prompt = "json" if is_json_task else language
        # If JSON task, we keep top-program JSON readable (pretty)
        # BUT we will escape braces before format() later.
        if is_json_task:
            if isinstance(initial_program, str) and initial_program.strip():
                initial_program = self._pretty_json(initial_program)
            if isinstance(current_program, str) and current_program.strip():
                current_program = self._pretty_json(current_program)
            if isinstance(parent_program, str) and parent_program.strip():
                parent_program = self._pretty_json(parent_program)
            else:
                parent_program = ""
        # Pick user template
        if template_key:
            user_template_key = template_key
        elif self.user_template_override:
            user_template_key = self.user_template_override
        else:
            user_template_key = "json_user" if is_json_task else (
                "diff_user" if diff_based_evolution else "full_rewrite_user"
            )
        user_template = self.template_manager.get_template(user_template_key)
        # Pick system message
        if self.system_template_override:
            system_message = self.template_manager.get_template(self.system_template_override)
        else:
            system_message = self.config.system_message
            if system_message in self.template_manager.templates:
                system_message = self.template_manager.get_template(system_message)
        # Evolution history
        evolution_history = self._format_evolution_history(
            previous_programs=previous_programs,
            top_programs=top_programs,
            inspirations=inspirations,
            language=language_for_prompt,
            feature_dimensions=feature_dimensions,
        )
        # Artifacts
        artifacts_section = ""
        if self.config.include_artifacts and program_artifacts:
            artifacts_section = self._render_artifacts(program_artifacts)
        # Apply stochastic variations
        if self.config.use_template_stochasticity:
            user_template = self._apply_template_variations(user_template)
        # ---- Keep prompt clean: shorten huge state JSON blocks (optional) ----
        # This reduces "杂乱" and makes user prompt closer to your example.
        initial_program_view = self._maybe_shorten_state_json(initial_program, "初始方案 initial_program（状态）")
        parent_program_view = self._maybe_shorten_state_json(parent_program, "上一代父方案 parent_program（状态）")
        current_program_view = self._maybe_shorten_state_json(current_program, "当前方案 current_program（状态）")
        # ---- CRITICAL: escape braces in inserted fields BEFORE format() ----
        evolution_history_safe = self._escape_braces_for_format(evolution_history)
        artifacts_section_safe = self._escape_braces_for_format(artifacts_section)
        initial_program_safe = self._escape_braces_for_format(initial_program_view)
        parent_program_safe = self._escape_braces_for_format(parent_program_view)
        current_program_safe = self._escape_braces_for_format(current_program_view)
        user_message = user_template.format(
            evolution_round=evolution_round,
            evolution_history=evolution_history_safe,
            initial_program=initial_program_safe,
            parent_program=parent_program_safe,
            current_program=current_program_safe,
            artifacts=artifacts_section_safe,
        )
        out = {"system": system_message, "user": user_message}
        # -------------------------
        # prompt dump (optional)
        # -------------------------
        try:
            if os.getenv("OPENEOLVE_DUMP_PROMPT", "0") not in ("0", "", "false", "False"):
                dump_dir = os.getenv(
                    "OPENEOLVE_DUMP_DIR",
                    "/mnt/shared-storage-user/llmbr-share/hezhishu/openevolve/openevolve/_prompt_dumps",
                )
                os.makedirs(dump_dir, exist_ok=True)
                dump_once = os.getenv("OPENEOLVE_DUMP_PROMPT_ONCE", "1") not in ("0", "", "false", "False")
                pid = os.getpid()
                if (not dump_once) or (pid not in _DUMPED_ONCE_BY_PID):
                    _DUMPED_ONCE_BY_PID.add(pid)
                    sample_id = None
                    try:
                        if isinstance(parsed_current, dict) and parsed_current.get("id"):
                            sample_id = str(parsed_current.get("id"))
                    except Exception:
                        sample_id = None
                    h = hashlib.md5((out["system"] + "\n" + out["user"]).encode("utf-8")).hexdigest()[:8]
                    ts = int(time.time() * 1000)
                    base = f"prompt_round{evolution_round}_pid{pid}_{ts}_{h}"
                    if sample_id:
                        base = f"{base}_{sample_id}"
                    path = os.path.join(dump_dir, base + ".json")
                    payload = {
                        "meta": {
                            "evolution_round": evolution_round,
                            "pid": pid,
                            "template_key": user_template_key,
                            "is_json_task": is_json_task,
                            "sample_id": sample_id,
                        },
                        "prompt": out,
                        "messages": [
                            {"role": "system", "content": out["system"]},
                            {"role": "user", "content": out["user"]},
                        ],
                    }
                    with open(path, "w", encoding="utf-8") as f:
                        json.dump(payload, f, ensure_ascii=False, indent=2)
                    print(f"[OPENEOLVE_DUMP_PROMPT] saved: {path}", file=sys.stderr, flush=True)
        except Exception as e:
            print(f"[OPENEOLVE_DUMP_PROMPT] failed: {e}", file=sys.stderr, flush=True)
        return out
    # ----------------------------- small helpers -----------------------------
    def _format_metrics_inline(self, metrics: Dict[str, Any], keys: Optional[List[str]] = None, limit: int = 6) -> str:
        if not isinstance(metrics, dict):
            return ""
        ordered: List[str] = []
        if "combined_score" in metrics:
            ordered.append("combined_score")
        if keys:
            for k in keys:
                if k in metrics and k not in ordered:
                    ordered.append(k)
        if not ordered:
            for k, v in metrics.items():
                if isinstance(v, (int, float)):
                    ordered.append(k)
                if len(ordered) >= limit:
                    break
        parts = []
        for k in ordered[:limit]:
            v = metrics.get(k)
            if isinstance(v, (int, float)):
                try:
                    parts.append(f"{k}: {v:.4f}")
                except Exception:
                    parts.append(f"{k}: {v}")
            else:
                parts.append(f"{k}: {v}")
        return ", ".join(parts)
    def _safe_fragment(self, key: str, **kwargs) -> str:
        try:
            return self.template_manager.get_fragment(key, **kwargs)
        except Exception:
            if kwargs:
                return f"{key}: " + ", ".join([f"{k}={v}" for k, v in kwargs.items()])
            return key
    # ----------------------------- evolution history -----------------------------
    def _format_evolution_history(
        self,
        previous_programs: List[Dict[str, Any]],
        top_programs: List[Dict[str, Any]],
        inspirations: List[Dict[str, Any]],
        language: str,
        feature_dimensions: Optional[List[str]] = None,
    ) -> str:
        feature_dimensions = feature_dimensions or []
        history_template = self.template_manager.get_template("evolution_history")
        previous_attempt_template = self.template_manager.get_template("previous_attempt")
        top_program_template = self.template_manager.get_template("top_program")
        is_json_task = (language or "").lower() == "json"
        lang_for_block = "json" if is_json_task else language
        # previous attempts
        previous_attempts_str = ""
        keep_n_prev = min(2, len(previous_programs))
        selected_previous = previous_programs[-keep_n_prev:] if keep_n_prev > 0 else []
        for i, program in enumerate(reversed(selected_previous)):
            attempt_number = i + 1
            changes = program.get("metadata", {}).get("changes", "未知修改")
            perf = self._format_metrics_inline(
                program.get("metrics", {}) or {},
                keys=["enob", "snr", "sfdr", "pw", "gain", "ugf", "pm", "iq", "sinad"],
                limit=7,
            )
            parent_metrics = program.get("metadata", {}).get("parent_metrics", {}) or {}
            program_metrics = program.get("metrics", {}) or {}
            comparable = []
            for k, v in program_metrics.items():
                pv = parent_metrics.get(k)
                if isinstance(v, (int, float)) and isinstance(pv, (int, float)):
                    comparable.append((v, pv))
            outcome = self._safe_fragment("outcome_mixed")
            if comparable:
                improved_all = all(v > pv for v, pv in comparable)
                regressed_all = all(v < pv for v, pv in comparable)
                if improved_all:
                    outcome = self._safe_fragment("outcome_all_improved")
                elif regressed_all:
                    outcome = self._safe_fragment("outcome_all_regressed")
            previous_attempts_str += (
                previous_attempt_template.format(
                    attempt_number=attempt_number,
                    changes=changes,
                    performance=perf,
                    outcome=outcome,
                )
                + "\n\n"
            )
        # top programs
        top_programs_str = ""
        selected_top = top_programs[: min(self.config.num_top_programs, len(top_programs))]
        for i, program in enumerate(selected_top):
            program_code = program.get("code", "") or ""
            if is_json_task:
                program_code = self._pretty_json(program_code)
            score = get_fitness_score(program.get("metrics", {}) or {}, feature_dimensions)
            m = program.get("metrics", {}) or {}
            key_features = []
            for k in ["combined_score", "enob", "sfdr", "snr", "pw", "gain", "ugf", "pm", "iq"]:
                if k in m:
                    v = m[k]
                    if isinstance(v, (int, float)):
                        key_features.append(f"{k}={v:.4f}")
                    else:
                        key_features.append(f"{k}={v}")
                if len(key_features) >= 3:
                    break
            if not key_features:
                key_features = ["参考样本（无可用指标摘要）"]
            top_programs_str += (
                top_program_template.format(
                    program_number=i + 1,
                    score=f"{score:.4f}",
                    language=lang_for_block,
                    program_snippet=program_code,
                    key_features=", ".join(key_features),
                )
                + "\n\n"
            )
        # diverse programs
        diverse_programs_str = ""
        if self.config.num_diverse_programs > 0 and len(top_programs) > self.config.num_top_programs:
            remaining = top_programs[self.config.num_top_programs:]
            num_diverse = min(self.config.num_diverse_programs, len(remaining))
            if num_diverse > 0:
                diverse_programs = random.sample(remaining, num_diverse)
                diverse_programs_str += "\n\n## 多样性样本\n\n"
                for i, program in enumerate(diverse_programs):
                    program_code = program.get("code", "") or ""
                    if is_json_task:
                        program_code = self._pretty_json(program_code)
                    score = get_fitness_score(program.get("metrics", {}) or {}, feature_dimensions)
                    key_features = ["不同思路/探索方向"]
                    diverse_programs_str += (
                        top_program_template.format(
                            program_number=f"D{i + 1}",
                            score=f"{score:.4f}",
                            language=lang_for_block,
                            program_snippet=program_code,
                            key_features=", ".join(key_features),
                        )
                        + "\n\n"
                    )
        inspirations_section_str = self._format_inspirations_section(
            inspirations=inspirations,
            language=lang_for_block,
            feature_dimensions=feature_dimensions,
        )
        return history_template.format(
            previous_attempts=previous_attempts_str.strip(),
            top_programs=(top_programs_str + diverse_programs_str).strip(),
            inspirations_section=inspirations_section_str,
        )
    def _format_inspirations_section(
        self,
        inspirations: List[Dict[str, Any]],
        language: str,
        feature_dimensions: Optional[List[str]] = None,
    ) -> str:
        if not inspirations:
            return ""
        feature_dimensions = feature_dimensions or []
        inspirations_section_template = self.template_manager.get_template("inspirations_section")
        inspiration_program_template = self.template_manager.get_template("inspiration_program")
        is_json_task = (language or "").lower() == "json"
        lang_for_block = "json" if is_json_task else language
        inspiration_programs_str = ""
        for i, program in enumerate(inspirations):
            program_code = program.get("code", "") or ""
            if is_json_task:
                program_code = self._pretty_json(program_code)
            score = get_fitness_score(program.get("metrics", {}) or {}, feature_dimensions)
            program_type = self._determine_program_type(program, feature_dimensions)
            unique_features = self._extract_unique_features(program)
            inspiration_programs_str += (
                inspiration_program_template.format(
                    program_number=i + 1,
                    score=f"{score:.4f}",
                    program_type=program_type,
                    language=lang_for_block,
                    program_snippet=program_code,
                    unique_features=unique_features,
                )
                + "\n\n"
            )
        return inspirations_section_template.format(inspiration_programs=inspiration_programs_str.strip())
    def _determine_program_type(self, program: Dict[str, Any], feature_dimensions: Optional[List[str]] = None) -> str:
        metadata = program.get("metadata", {}) or {}
        score = get_fitness_score(program.get("metrics", {}) or {}, feature_dimensions or [])
        if metadata.get("diverse", False):
            return "多样性样本"
        if metadata.get("migrant", False):
            return "迁移样本"
        if metadata.get("random", False):
            return "随机样本"
        if score >= 0.8:
            return "高分样本"
        elif score >= 0.6:
            return "备选方案"
        elif score >= 0.4:
            return "实验性方案"
        return "探索性方案"
    def _extract_unique_features(self, program: Dict[str, Any]) -> str:
        features: List[str] = []
        metadata = program.get("metadata", {}) or {}
        changes = metadata.get("changes")
        if isinstance(changes, str) and changes:
            if self.config.include_changes_under_chars and len(changes) < self.config.include_changes_under_chars:
                features.append(f"修改摘要：{changes}")
        metrics = program.get("metrics", {}) or {}
        cs = metrics.get("combined_score")
        if isinstance(cs, (int, float)):
            if cs >= 0.8:
                features.append(f"combined_score 很高（{cs:.3f}）")
            elif cs <= 0.2:
                features.append(f"combined_score 偏低（{cs:.3f}）")
            else:
                features.append(f"combined_score={cs:.3f}")
        others = []
        for k in ["enob", "sfdr", "snr", "pw", "gain", "ugf", "pm", "iq", "sinad"]:
            if k in metrics and k != "combined_score":
                v = metrics[k]
                if isinstance(v, (int, float)):
                    others.append(f"{k}={v:.4f}")
                else:
                    others.append(f"{k}={v}")
            if len(others) >= 3:
                break
        if others:
            features.append("指标：" + ", ".join(others))
        code = program.get("code", "")
        obj = self._try_load_json(code) if isinstance(code, str) else None
        if isinstance(obj, dict):
            vars_dict = obj.get("variables", obj)
            if isinstance(vars_dict, dict):
                keys = list(vars_dict.keys())
                preview_k = keys[: min(6, len(keys))]
                preview_pairs = []
                for k in preview_k:
                    v = vars_dict.get(k)
                    if isinstance(v, (str, int, float)):
                        preview_pairs.append(f"{k}={v}")
                features.append(f"参数数量：{len(vars_dict)}；示例：{', '.join(preview_pairs)}")
        if not features:
            features.append(f"{self._determine_program_type(program)} 的一种做法")
        return ", ".join(features[:4])
    # ----------------------------- template utils -----------------------------
    def _apply_template_variations(self, template: str) -> str:
        result = template
        for key, variations in (self.config.template_variations or {}).items():
            if variations and f"{{{key}}}" in result:
                chosen = random.choice(variations)
                result = result.replace(f"{{{key}}}", chosen)
        return result
    # ----------------------------- artifacts -----------------------------
    def _render_artifacts(self, artifacts: Dict[str, Union[str, bytes]]) -> str:
        if not artifacts:
            return ""
        sections = []
        for key, value in artifacts.items():
            content = self._safe_decode_artifact(value)
            if self.config.max_artifact_bytes and len(content) > self.config.max_artifact_bytes:
                content = content[: self.config.max_artifact_bytes] + "\n...（已截断）"
            sections.append(f"### {key}\n```\n{content}\n```")
        return "## 上一次评估输出 / 报错信息\n\n" + "\n\n".join(sections) if sections else ""
    def _safe_decode_artifact(self, value: Union[str, bytes]) -> str:
        if isinstance(value, str):
            return self._apply_security_filter(value) if self.config.artifact_security_filter else value
        if isinstance(value, bytes):
            try:
                decoded = value.decode("utf-8", errors="replace")
                return self._apply_security_filter(decoded) if self.config.artifact_security_filter else decoded
            except Exception:
                return f"<二进制数据：{len(value)} bytes>"
        return str(value)
    def _apply_security_filter(self, text: str) -> str:
        import re
        ansi_escape = re.compile(r"\x1B(?:[@-Z\\-_]|\[[0-?]*[ -/]*[@-~])")
        filtered = ansi_escape.sub("", text)
        secret_patterns = [
            (r"[A-Za-z0-9]{32,}", "<REDACTED_TOKEN>"),
            (r"sk-[A-Za-z0-9]{48}", "<REDACTED_API_KEY>"),
            (r"password[=:]\s*[^\s]+", "password=<REDACTED>"),
            (r"token[=:]\s*[^\s]+", "token=<REDACTED>"),
        ]
        for pattern, replacement in secret_patterns:
            filtered = re.sub(pattern, replacement, filtered, flags=re.IGNORECASE)
        return filtered
